_logFailover(fromProvider, toProvider, modality) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    event: 'failover',
    from: fromProvider,
    to: toProvider,
    modality,
  };
  this.logs.push(logEntry);
  if (this.logs.length > 100) this.logs.shift();
