        {/* Footer */}
        <div className="text-center text-xs text-muted-foreground pb-4">
          HireLoop AI Health Dashboard &middot; Auto-refreshes every 30 seconds &middot; Last update: {lastRefresh.toLocaleString()}
        </div>
      </div>
    </div>
  )
}

